section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/design-system-impact-queue.json",
  "title": "Design System Impact Queue",
  "type": "object",
  "required": [
    "artefact_id",
    "queue_id",
    "review_window",
    "items",
    "triage_decision",
    "owner_assigned",
    "status",
    "shipped_in_release",
    "rejected_reason",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "queue_id": {
      "type": "string",
      "description": "queue_id",
      "minLength": 1
    },
    "review_window": {
      "type": "string",
      "description": "review_window",
      "minLength": 1
    },
    "items": {
      "type": "array",
      "description": "items (array)",
      "minItems": 1
    },
    "triage_decision": {
      "type": "string",
      "description": "triage_decision",
      "minLength": 1
    },
    "owner_assigned": {
      "type": "array",
      "description": "owner_assigned (array)",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "shipped_in_release": {
      "type": "string",
      "description": "shipped_in_release",
      "minLength": 1
    },
    "rejected_reason": {
      "type": "string",
      "description": "rejected_reason",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
